####################
 # FUNCTION iauracadmakearrayofarray #
####################
def iauracadmakearrayofarray(lis,low1,u1,low2,u2,):
	'''
	:param lis
	:type lis:(null)
	:param low1
	:type low1:INTEGER
	:param u1
	:type u1:INTEGER
	:param low2
	:type low2:INTEGER
	:param u2
	:type u2:INTEGER
	'''
	if (((u1 - low1)  +  1)  !=  SIZEOF(lis)):
		return  None
	if (((u2 - low2)  +  1)  !=  SIZEOF(lis[1])):
		return  None
	res = [iauracadlisttoarray(lis[1],low2,u2),(u1 - low1)  +  1]
	for  i in range(2,HIINDEX(lis),1):
		if (((u2 - low2)  +  1)  !=  SIZEOF(lis[i])):
			return  None
		res[(low1  +  i) - 1] = iauracadlisttoarray(lis[i],low2,u2)
	return res

####################
 # FUNCTION iauracadcurvedim #
####################
def iauracadcurvedim(curve,):
	'''
	:param curve
	:type curve:iauracadcurve
	'''
	if ('Iauracad4.IauracadLINE'  ==  TYPEOF(curve)):
		return curve.iauracadline.pnt.dim
	if ('Iauracad4.IauracadCONIC'  ==  TYPEOF(curve)):
		return curve.iauracadconic.position.dim
	if ('Iauracad4.IauracadPOLYLINE'  ==  TYPEOF(curve)):
		return curve.iauracadpolyline.points[1].dim
	if ('Iauracad4.IauracadTRIMMEDCURVE'  ==  TYPEOF(curve)):
		return iauracadcurvedim(curve.iauracadtrimmedcurve.basiscurve)
	if ('Iauracad4.IauracadCOMPOSITECURVE'  ==  TYPEOF(curve)):
		return curve.iauracadcompositecurve.segments[1].dim
	if ('Iauracad4.IauracadBSPLINECURVE'  ==  TYPEOF(curve)):
		return curve.iauracadbsplinecurve.controlpointslist[1].dim
	if ('Iauracad4.IauracadOFFSETCURVE2D'  ==  TYPEOF(curve)):
		return 2
	if ('Iauracad4.IauracadOFFSETCURVE3D'  ==  TYPEOF(curve)):
		return 3
	if ('Iauracad4.IauracadPCURVE'  ==  TYPEOF(curve)):
		return 3
	return  None

####################
 # FUNCTION iauracadsamedirection #
####################
def iauracadsamedirection(dir1,dir2,epsilon,):
	'''
	:param dir1
	:type dir1:iauracaddirection
	:param dir2
	:type dir2:iauracaddirection
	:param epsilon
	:type epsilon:REAL
	'''
	if (SIZEOF(dir1.directionratios)  >  2):
		dir1z = dir1.directionratios[3]
	if (SIZEOF(dir2.directionratios)  >  2):
		dir2z = dir2.directionratios[3]
	return (iauracadsamevalue(dir1x,dir2x,epsilon)  and  iauracadsamevalue(dir1y,dir2y,epsilon))  and  iauracadsamevalue(dir1z,dir2z,epsilon)

####################
 # FUNCTION iauracadlisttoarray #
####################
def iauracadlisttoarray(lis,low,u,):
	'''
	:param lis
	:type lis:(null)
	:param low
	:type low:INTEGER
	:param u
	:type u:INTEGER
	'''
	n = SIZEOF(lis)
	if (n  !=  ((u - low)  +  1)):
		return  None
	else:
		res = [lis[1],n]
		for  i in range(2,n,1):
			res[(low  +  i) - 1] = lis[i]
		return res

