####################
 # FUNCTION iauracadcorrectunitassignment #
####################
def iauracadcorrectunitassignment(units,):
	'''
	:param units
	:type units:(null)
	'''
	namedunitnumber = SIZEOF(None)
	derivedunitnumber = SIZEOF(None)
	monetaryunitnumber = SIZEOF(None)
	for  i in range(1,SIZEOF(units),1):
		if (('Iauracad4.IauracadNAMEDUNIT'  ==  TYPEOF(units[i]))  and  ( not (units[i].iauracadnamedunit.unittype  ==  iauracadunitenum.userdefined))):
			namedunitnames = namedunitnames  +  units[i].iauracadnamedunit.unittype
		if (('Iauracad4.IauracadDERIVEDUNIT'  ==  TYPEOF(units[i]))  and  ( not (units[i].iauracadderivedunit.unittype  ==  iauracadderivedunitenum.userdefined))):
			derivedunitnames = derivedunitnames  +  units[i].iauracadderivedunit.unittype
	return ((SIZEOF(namedunitnames)  ==  namedunitnumber)  and  (SIZEOF(derivedunitnames)  ==  derivedunitnumber))  and  (monetaryunitnumber  <=  1)

####################
 # FUNCTION iauracaddotproduct #
####################
def iauracaddotproduct(arg1,arg2,):
	'''
	:param arg1
	:type arg1:iauracaddirection
	:param arg2
	:type arg2:iauracaddirection
	'''
	if (( not EXISTS(arg1))  or  ( not EXISTS(arg2))):
		scalar =  None
	else:
		if (arg1.dim  !=  arg2.dim):
			scalar =  None
		else:
			# begin/end block
			vec1 = iauracadnormalise(arg1)
			vec2 = iauracadnormalise(arg2)
			ndim = arg1.dim
			scalar = 0
			for  i in range(1,ndim,1):
				scalar = scalar  +  (vec1.directionratios[i]  *  vec2.directionratios[i])
	return scalar

####################
 # FUNCTION iauracadfirstprojaxis #
####################
def iauracadfirstprojaxis(zaxis,arg,):
	'''
	:param zaxis
	:type zaxis:iauracaddirection
	:param arg
	:type arg:iauracaddirection
	'''
	if ( not EXISTS(zaxis)):
		return  None
	else:
		z = iauracadnormalise(zaxis)
		if ( not EXISTS(arg)):
			if (z.directionratios  !=  [1,0,0]):
				v = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([1,0,0])
			else:
				v = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([0,1,0])
		else:
			if (arg.dim  !=  3):
				return  None
			if (iauracadcrossproduct(arg,z).magnitude  ==  0):
				return  None
			else:
				v = iauracadnormalise(arg)
		xvec = iauracadscalartimesvector(iauracaddotproduct(v,z),z)
		xaxis = iauracadvectordifference(v,xvec).orientation
		xaxis = iauracadnormalise(xaxis)
	return xaxis

