####################
 # FUNCTION iauracadpathheadtotail #
####################
def iauracadpathheadtotail(apath,):
	'''
	:param apath
	:type apath:iauracadpath
	'''
	n = SIZEOF(apath.edgelist)
	for  i in range(2,n,1):
		p = p  and  (apath.edgelist[i - 1].edgeend  ==  apath.edgelist[i].edgestart)
	return p

####################
 # FUNCTION iauracadsecondprojaxis #
####################
def iauracadsecondprojaxis(zaxis,xaxis,arg,):
	'''
	:param zaxis
	:type zaxis:iauracaddirection
	:param xaxis
	:type xaxis:iauracaddirection
	:param arg
	:type arg:iauracaddirection
	'''
	if ( not EXISTS(arg)):
		v = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([0,1,0])
	else:
		v = arg
	temp = iauracadscalartimesvector(iauracaddotproduct(v,zaxis),zaxis)
	yaxis = iauracadvectordifference(v,temp)
	temp = iauracadscalartimesvector(iauracaddotproduct(v,xaxis),xaxis)
	yaxis = iauracadvectordifference(yaxis,temp)
	yaxis = iauracadnormalise(yaxis)
	return yaxis.orientation

####################
 # FUNCTION iauracadderivedimensionalexponents #
####################
def iauracadderivedimensionalexponents(unitelements,):
	'''
	:param unitelements
	:type unitelements:(null)
	'''
	for  i in range(LOINDEX(unitelements),HIINDEX(unitelements),1):
		result.lengthexponent = result.lengthexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.lengthexponent)
		result.massexponent = result.massexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.massexponent)
		result.timeexponent = result.timeexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.timeexponent)
		result.electriccurrentexponent = result.electriccurrentexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.electriccurrentexponent)
		result.thermodynamictemperatureexponent = result.thermodynamictemperatureexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.thermodynamictemperatureexponent)
		result.amountofsubstanceexponent = result.amountofsubstanceexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.amountofsubstanceexponent)
		result.luminousintensityexponent = result.luminousintensityexponent  +  (unitelements[i].exponent  *  unitelements[i].unit.dimensions.luminousintensityexponent)
	return result

####################
 # FUNCTION iauracadbooleanchoose #
####################
def iauracadbooleanchoose(b,choice1,choice2,):
	'''
	:param b
	:type b:BOOLEAN
	:param choice1
	:type choice1:(null)
	:param choice2
	:type choice2:(null)
	'''
	if (b):
		return choice1
	else:
		return choice2

####################
 # FUNCTION iauracadscalartimesvector #
####################
def iauracadscalartimesvector(scalar,vec,):
	'''
	:param scalar
	:type scalar:REAL
	:param vec
	:type vec:iauracadvectorordirection
	'''
	if (( not EXISTS(scalar))  or  ( not EXISTS(vec))):
		return  None
	else:
		if ('Iauracad4.IauracadVECTOR'  ==  TYPEOF(vec)):
			v = vec.iauracadvector.orientation
			mag = scalar  *  vec.iauracadvector.magnitude
		else:
			v = vec
			mag = scalar
		if (mag  <  0):
			for  i in range(1,SIZEOF(v.directionratios),1):
				v.directionratios[i] = -v.directionratios[i]
			mag = -mag
		result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(iauracadnormalise(v),mag)
	return result

####################
 # FUNCTION iauracadgetbasissurface #
####################
def iauracadgetbasissurface(c,):
	'''
	:param c
	:type c:iauracadcurveonsurface
	'''
	surfs = []
	if ('Iauracad4.IauracadPCURVE'  ==  TYPEOF(c)):
		surfs = [c.iauracadpcurve.basissurface]
	else:
		if ('Iauracad4.IauracadCOMPOSITECURVEONSURFACE'  ==  TYPEOF(c)):
			n = SIZEOF(c.iauracadcompositecurve.segments)
			surfs = iauracadgetbasissurface(c.iauracadcompositecurve.segments[1].parentcurve)
			if (n  >  1):
				for  i in range(2,n,1):
					surfs = surfs  *  iauracadgetbasissurface(c.iauracadcompositecurve.segments[1].parentcurve)
	return surfs

