 # FUNCTION iauracadconvertdirectioninto2d #
####################
def iauracadconvertdirectioninto2d(direction,):
	'''
	:param direction
	:type direction:iauracaddirection
	'''
	direction2d.directionratios[1] = direction.directionratios[1]
	direction2d.directionratios[2] = direction.directionratios[2]
	return direction2d

####################
 # FUNCTION iauracadorthogonalcomplement #
####################
def iauracadorthogonalcomplement(vec,):
	'''
	:param vec
	:type vec:iauracaddirection
	'''
	if (( not EXISTS(vec))  or  (vec.dim  !=  2)):
		return  None
	else:
		result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([-vec.directionratios[2],vec.directionratios[1]])
		return result

####################
 # FUNCTION iauracadloopheadtotail #
####################
def iauracadloopheadtotail(aloop,):
	'''
	:param aloop
	:type aloop:iauracadedgeloop
	'''
	n = SIZEOF(aloop.edgelist)
	for  i in range(2,n,1):
		p = p  and  (aloop.edgelist[i - 1].edgeend  ==  aloop.edgelist[i].edgestart)
	return p

