####################
 # FUNCTION iauracadconstraintsparambspline #
####################
def iauracadconstraintsparambspline(degree,upknots,upcp,knotmult,knots,):
	'''
	:param degree
	:type degree:INTEGER
	:param upknots
	:type upknots:INTEGER
	:param upcp
	:type upcp:INTEGER
	:param knotmult
	:type knotmult:(null)
	:param knots
	:type knots:(null)
	'''
	sum = knotmult[1]
	for  i in range(2,upknots,1):
		sum = sum  +  knotmult[i]
	if ((((degree  <  1)  or  (upknots  <  2))  or  (upcp  <  degree))  or  (sum  !=  ((degree  +  upcp)  +  2))):
		result = FALSE
		return result
	k = knotmult[1]
	if ((k  <  1)  or  (k  >  (degree  +  1))):
		result = FALSE
		return result
	for  i in range(2,upknots,1):
		if ((knotmult[i]  <  1)  or  (knots[i]  <=  knots[i - 1])):
			result = FALSE
			return result
		k = knotmult[i]
		if ((i  <  upknots)  and  (k  >  degree)):
			result = FALSE
			return result
		if ((i  ==  upknots)  and  (k  >  (degree  +  1))):
			result = FALSE
			return result
	return result

####################
 # FUNCTION iauracadcrossproduct #
####################
def iauracadcrossproduct(arg1,arg2,):
	'''
	:param arg1
	:type arg1:iauracaddirection
	:param arg2
	:type arg2:iauracaddirection
	'''
	if ((( not EXISTS(arg1))  or  (arg1.dim  ==  2))  or  (( not EXISTS(arg2))  or  (arg2.dim  ==  2))):
		return  None
	else:
		# begin/end block
		v1 = iauracadnormalise(arg1).iauracaddirection.directionratios
		v2 = iauracadnormalise(arg2).iauracaddirection.directionratios
		res = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([(v1[2]  *  v2[3]) - (v1[3]  *  v2[2]),(v1[3]  *  v2[1]) - (v1[1]  *  v2[3]),(v1[1]  *  v2[2]) - (v1[2]  *  v2[1])])
		mag = 0
		for  i in range(1,3,1):
			mag = mag  +  (res.directionratios[i]  *  res.directionratios[i])
		if (mag  >  0):
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(res,SQRT(mag))
		else:
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(arg1,0)
		return result

